55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	};
61	
62	const FIRST_INSURANCE_SURCHARGE = 1.1;
63	const PROCESSING_FEE = 5;
64	const FLOAT_PRECISION_DIGITS = 6;
65	
66	const quotePremium = (step: QuoteStep): number => {
67	  const itemTotal = step.items.reduce(
68	    (sum, item) => sum + BASE_PREMIUM[item.type] * FIRST_INSURANCE_SURCHARGE,
69	    0,
70	  );
71	  const premium = itemTotal + PROCESSING_FEE;
72	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
73	};
74	
75	export const runScenario = (scenario: Scenario): ScenarioResult => {
76	  return {
77	    results: scenario.steps.map((step) => ({
78	      premium: quotePremium(step as QuoteStep),
79	    })),
80	  };
81	};
