1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Base premiums for single main items (incl. first-insurance +10% and 5 G fee) ---
6	  // For a newcomer (0 years, first quote): premium = base * 1.10 + 5
7	  it("empty item list → premium 5 G (only the processing fee)", () => {
8	    const result = runScenario({
9	      customer: { yearsWithMHPCO: 0 },
10	      steps: [{ op: "quote", items: [] }],
11	    });
12	    expect(result.results[0]).toEqual({ premium: 5 });
13	  });
14	  it("single sword (base 100) → premium 100*1.10 + 5 = 115 G", () => {
15	    const result = runScenario({
16	      customer: { yearsWithMHPCO: 0 },
17	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
18	    });
19	    expect(result.results[0]).toEqual({ premium: 115 });
20	  });
21	  it("single amulet (base 60) → premium 60*1.10 + 5 = 71 G", () => {
22	    const result = runScenario({
23	      customer: { yearsWithMHPCO: 0 },
24	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
25	    });
26	    expect(result.results[0]).toEqual({ premium: 71 });
27	  });
28	  it("single staff (base 80) → premium 80*1.10 + 5 = 93 G", () => {
29	    const result = runScenario({
30	      customer: { yearsWithMHPCO: 0 },
31	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
32	    });
33	    expect(result.results[0]).toEqual({ premium: 93 });
34	  });
35	  it("single potion (base 40) → premium 40*1.10 + 5 = 49 G", () => {
36	    const result = runScenario({
37	      customer: { yearsWithMHPCO: 0 },
38	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
39	    });
40	    expect(result.results[0]).toEqual({ premium: 49 });
41	  });
42	
43	  // --- Components and building blocks (base premium focus) ---
44	  it.todo("1 rune (base 25) → premium 25*1.10 + 5 = 32.5 → rounded up 33 G");
45	  it.todo("2 runes → base 50 G");
46	  it.todo("3 runes → base 60 G (block applies)");
47	  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
48	  it.todo("7 runes → base 175 G (one block of 3 + 4 singles = 60 + 100)");
49	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
50	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
51	
52	  // --- Item-specific premium modifiers ---
53	  it.todo("cursed sword adds 50% of its base premium (curse surcharge)");
54	  it.todo("sword with enchantment exactly 5 → high-enchantment +30% surcharge");
55	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
56	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
57	
58	  // --- Policy-wide modifiers ---
59	  it.todo("customer with exactly 2 years → 20% loyalty discount on policy base");
60	  it.todo("customer with 1 year → no loyalty discount");
61	  it.todo("second quote in scenario → 15% follow-up contract discount on policy base");
62	  it.todo("first insurance +10% surcharge applies to each item even on a follow-up contract");
63	
64	  // --- Modifier scope on multi-item policies ---
65	  it.todo("cursed sword + plain amulet → curse surcharge is 50% of cursed sword base only (210 before fee/modifiers)");
66	
67	  // --- Rounding ---
68	  it.todo("premium yielding 197.5 G → rounded up to 198 G");
69	
70	  // --- Integration examples ---
71	  it.todo("newcomer cursed sword (0y, ench 3) → premium 165 G");
72	  it.todo("long-standing 2nd contract (3y, cursed sword ench 7) → premium 160 G");
73	
74	  // --- Claim processing: standard reimbursement ---
75	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 G (full minus 100 deductible)");
76	  it.todo("rune damage 200 (value 250) → payout 100 G (full minus 100 deductible, no special clause)");
77	  it.todo("claim reports remainingCap after a payout");
78	
79	  // --- Claim processing: special clauses ---
80	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 G (full reimbursement then deductible)");
81	  it.todo("steel sword, ench 9, damage 1000 → payout 400 G (50% then deductible)");
82	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 G (50% wins over dragon, then deductible)");
83	  it.todo("dragon-material sword, ench exactly 8, damage 1000 → payout 400 G (high-ench clause then deductible)");
84	
85	  // --- Deductible per damage event ---
86	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");
87	
88	  // --- Multiple items of the same type ---
89	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
90	  it.todo("two sword damages on a two-sword policy → each treated as separate damage with own deductible");
91	  it.todo("more damage entries of a type than insured items → claim rejected (throws)");
92	
93	  // --- Cap exhaustion ---
94	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
95	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
96	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount does not affect sum)");
97	  it.todo("two successive 1500 claims on a 1000-sword policy → payouts 1400 then 600, remaining cap 600 then 0");
98	
99	  // --- Error / edge cases ---
100	  it.todo("quote with unknown item type → throws (CLI non-zero exit)");
101	  it.todo("claim references item not in policy → throws");
102	  it.todo("claim with negative damage amount → throws");
103	});
